var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"천장이 무너져서 생긴 잔해가 길을 막고 있습니다.","JPN":"天井が崩れ落ちてできた残骸が道を塞いでます。","ENG":"The debris from the collapse is blocking our way.","TWN":"天花板坍塌的殘骸擋住了去路。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이 앞은 살펴보기 어렵겠군요.","JPN":"この先を確かめるのは難しそうですね。","ENG":"It's going to be difficult trying to see what's on the other end.","TWN":"這前面沒辦法查看了呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"그, 그만 돌아가시죠. 부학회장님. 몸도 편찮으시다고 하던데…….","JPN":"も、もう戻りましょう。副学会長。お身体も本調子ではないと聞きましたし……","ENG":"L-let's go back, Vice President. I heard you are... not feeling well...","TWN":"我…我們回去吧，副學會長。聽說你身體也不好……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAN_NPC_ESPR2_A","text":{"KOREA":"맞습니다. 설마 그 불손한 외지인이 이런 곳으로 숨어 들었으려고요.","JPN":"そうですよ。あの不遜なよそ者がこんなところに潜り込むとは思えません。","ENG":"I agree. There's no way that insolent outlander will hide somewhere like here.","TWN":"沒錯。那個不速之客，應該也不會躲到這種地方來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳、咳咳……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 사람이 지나간 흔적은 이 방향을 가리키고 있어요.","JPN":"いいえ。人が通った跡はこちらの方向を示しています。","ENG":"No, the tracks all point to here.","TWN":"不，這裡有人經過的痕跡。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이것 보세요. 탄창이 바닥에 떨어져 있잖아요? 정신없이 도망치다가 떨어뜨린 거겠죠.","JPN":"見てください。弾倉が床に落ちていますわ。あわてて逃げていて落としてしまったのでしょう。","ENG":"Look. See that empty magazine on the floor? It must've slipped out while he was running from us.","TWN":"看看這個。地面上有個彈匣不是嘛？應該是他慌亂逃跑時掉下來的吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 영지에 들어왔다던 그 외지인, 붙잡으면 해부학 실습용으로 쓸 생각 아니었나요?","JPN":"それに領地に入ったというその者、捕まえたら解剖学の実習に使うつもりだったのではありませんか？","ENG":"Also, weren't you planning on using that outlander's cadaver for anatomy practice?","TWN":"還有，你不是想抓到進入領地的那個外地人後，用於解剖學實習嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그렇습니다. 허락 받지 않은 침입자의 처우는 현장에서 판단하는 것이 학회의 규정이기에.","JPN":"そのとおりです。無断侵入した者の処遇は現場で判断するのが学会のきまりですので。","ENG":"Yes. The Society's rules dictate that anyone who enters without permission is to have their fate decided upon capture.","TWN":"是的。未經允許的入侵者，可以在現場判斷如何處置，這是學會的規定。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"길을 잃은 사람이면 곱게 돌려보내 줘야죠.","JPN":"道に迷った人であればちゃんと帰してあげるべきですわ。","ENG":"But let him go if he was lost and wandered in.","TWN":"如果是迷路的人，就應該好好地送他離開。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"앞으로 영지에서 해부학 실습을 할 때는 합법적으로 제공되는 카데바를 사용하세요.","JPN":"これから領地で解剖学の実習をする場合は、合法的に提供された献体を使ってください。","ENG":"From now on, you are only allowed to use legally obtained cadavers for anatomy practices within the estate.","TWN":"以後在領地進行解剖學實習時，都要使用合法提供的屍體。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……예. 의학부에 전파하겠습니다.","JPN":"……承知しました。医学部に伝えておきます。","ENG":"...Yes, ma'am. I'll relay the message to the medical department.","TWN":"……是的，我會傳達給醫學院。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"흐흥, 까탈스럽긴. 원래 들키지만 않으면 합법 아닐까?","JPN":"フフン、生真面目ね。バレなきゃ全部合法じゃないの？","ENG":"Hmph. Why so uptight? Also, it's not illegal if they don't catch you in the act, right?","TWN":"嗯哼，真苛刻啊。只要不被發現，就算是合法的吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쓸데없는 소리 말고 기름등 좀 들어 줘요.","JPN":"余計なことを言ってないで、ちょっとランタンを持っていてください。","ENG":"Stop your nonsense and hold the oil lamp for me.","TWN":"少廢話，快幫我提著油燈。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이럴 줄 알고 서재에서 지하 수로 설계도를 찾아 왔거든요.","JPN":"こういうこともあろうかと、書斎から地下水路の設計図を持ってきたのです。","ENG":"I brought the blueprints for the underground waterway from the study in case this would happen.","TWN":"我就知道會這樣，所以從書房找來了地下水道的設計圖。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지어진 지 수백 년은 된 것 같던데…… 어디……","JPN":"作られてから数百年は経過しているようですが……さて……","ENG":"Let me see here... It seems as if it has been built centuries ago...","TWN":"好像已經建成幾百年了……我看看……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"우와, 완전 미로네. 길치인 사람은 평생 헤매다가 뼈만 남겠어.","JPN":"うわ、完全に迷路だね。方向音痴は一生彷徨って骨になっちゃいそう。","ENG":"Wow... It's like a maze. Anyone with a poor sense of direction will end up and a pile of bones here, don't you think?","TWN":"哇啊，這裡完全是個迷宮。如果是路癡的話，我看走到老死也走不出去吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"아주 옛날에는 영지 바깥에서 온 외지인들을 버리던 곳이라고 들었습니다.","JPN":"その昔は領地の外から来た者を捨てていた場所だったと聞きました。","ENG":"I heard this place was where we threw out all the outlanders back in the day.","TWN":"聽說很久以前，這裡是丟棄外地人的地方。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MAN_NPC_ESPR2_C","text":{"KOREA":"요새야 함부로 숲에 발을 들이지 않아서 쓸 일이 없다지만요.","JPN":"最近は不用意に森に足を踏み入れないので、使うことがなくなっているようですが。","ENG":"But these days, they don't dare come close, so we don't use it as much.","TWN":"因為近來外地人不會輕易踏入森林，所以才會荒廢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"영지 한복판에서 총까지 쏴댄 외지인입니다. 그냥 여기서 죽게 내버려 두시죠.","JPN":"領地の真ん中で発砲までした輩です。助けずここで死んでもらいましょう。","ENG":"This outlander fired his gun in the middle of the estate. We should make him rot down here.","TWN":"那個外地人剛才在領地中心還開了槍，就讓他死在這裡吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 그 사람도 영지의 풍경이 낯설어서 과민하게 반응했을 거예요.","JPN":"いいえ。その人も領地の景色に慣れていなかったので、過敏に反応してしまったのでしょう。","ENG":"No. It was a mere overreaction because the estate's surroundings were unfamiliar to him.","TWN":"不，那個人也是因為對領地的情況感到陌生，才會有那麼激烈的反應。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"주제 넘게 부학회장님의 결정에 토를 다는군요. 도축하시겠습니까.","JPN":"身の程もわきまえず副学会長の決定に口出しするとは。屠畜しましょうか。","ENG":"How dare he question Ms. Vice President? I should slaughter him right now.","TWN":"竟敢不自量力地反駁副學會長的決定。我來幹掉他。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"힉, 히익…….","JPN":"ひっ、ひいっ……","ENG":"E-eeek!","TWN":"嗚…嗚…"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일전에도 말씀드렸을 텐데요. 외지인도 주민들도 저에게는 모두 같은 사람들이라고.","JPN":"前にもお話したはずです。よそ者も住民も、私にはみんな同じ人間であると。","ENG":"I believe I have mentioned it before. Resident or not, they are all people in my eyes.","TWN":"之前我應該也說過。不管是外地人還是居民，對我來說都是一樣的人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니 죽게 내버려 두라느니, 도축이라느니 같은 말은 제 앞에서 꺼내지 마세요.","JPN":"死んでもらうとか、屠畜とか、そういう話は私の前でしないでください。","ENG":"So please refrain from mentioning anything about making them rot or slaughtering in front of me.","TWN":"所以，不要再在我面前說什麼讓他死在這裡吧，幹掉他之類的話。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"가, 감사합니다. 부학회장님…….","JPN":"あ、ありがとうございます。副学会長……","ENG":"Th-thank you, ma'am...","TWN":"謝…謝謝你，副學會長……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ございません。","ENG":"...My apologies.","TWN":"……非常抱歉。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 여기 사람들 생긴 게 개성 넘치긴 해.","JPN":"あはは、ここの人たちって個性的だからさ。","ENG":"Ahahaha! Yeah, everyone here looks kinda funny.","TWN":"哈哈哈，這裡的人長得確實很有特色。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"침식체만 잡던 용병들이라면 놀라 자빠져서 방아쇠부터 당길 만도 하지, 뭐.","JPN":"侵食体と戦ってた傭兵ならびっくりして、とっさに引き金を引いちゃうと思うな。","ENG":"If he's a merc who only killed C.O.s before, I'm certain he freaked out and just went guns a-blazing.","TWN":"如果只是負責抓捕侵蝕體的傭兵，會被嚇到並先扣動扳機也情有可原。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좀 조용히 하세요, 리벳.","JPN":"ちょっと静かにしてください、リベット。","ENG":"Silence, Rivet.","TWN":"你閉嘴，里維。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아잉~ 나한테까지 야박하게 굴지 말고~","JPN":"あ～ん、アタシにまで冷たくあたらないでよ～","ENG":"Aw, come on! Don't be so hard on me.","TWN":"嗚嗚～別對我這麼凶嘛～"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……비비적거리지도 말아 주시고요.","JPN":"……すり寄ってこないでください。","ENG":"...Will you please give me some personal space?","TWN":"……也不要扭來扭去的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그보다 이 잔해 뒤쪽은 텅 비어 있는 공간이네요.","JPN":"それより、この残骸の後ろ側は開けた空間のようですね。","ENG":"In any case, it appears that the space behind the debris is empty.","TWN":"對了，這殘骸後面是個空曠的空間。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"빗물을 저장하는 용도 같던데…. 확인해 봐야겠어요.","JPN":"雨水を貯めておく場所のようですが……確認してみましょう。","ENG":"It looks like a rainwater collection system... We should check it out.","TWN":"好像是用來儲存雨水的……我得確認一下。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"확 쏴서 터뜨려 버릴까? 손이 근질근질하던 참인데?","JPN":"撃って爆発させちゃう？　ちょうどウズウズしてたところなんだ。","ENG":"Should I blow it up? My finger's just itching to pull the trigger!","TWN":"要開槍打爆嗎？我正手癢呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지은 지 수백 년은 더 된 시설이에요. 함부로 쐈다가 무너지기라도 하면……","JPN":"建てられて数百年は経つ施設なのですよ。むやみに撃って崩れでもしたら……","ENG":"This place was built centuries ago. If you blow it up and the roof collapses on us–","TWN":"這個設施建成有幾百年了。隨便開槍說我怕會垮掉……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"빵야!","JPN":"バーン！","ENG":"BANG!","TWN":"砰！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사람 말을 끝까지 들으라고! 이 미치광이야!","JPN":"人の話は最後まで聞きなさい！　この狂人！","ENG":"Did you not hear what I just said?! You lunatic!","TWN":"拜託你聽我說完！你這個瘋子！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 괜찮아. 내 덕분에 기어 들어갈 쥐구멍 찾는 수고는 덜었잖아.","JPN":"あはは、大丈夫だよ。おかげであっち側に行ける狭い穴を探さなくてもよくなったじゃん。","ENG":"Ahahaha! It's fine. But now, you have a hole to crawl in and out of, all thanks to me!","TWN":"哈哈哈，沒關係。多虧了我，你都不用費力去尋找可以爬進去的老鼠洞了吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"자! 얼른 확인하고 오자!","JPN":"さっさと確認して来ようよ！","ENG":"C'mon! Let's take a quick lookie!","TWN":"好了！快去看看吧！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오우, 죄송. 역시 세입자가 계셨네.","JPN":"おおっ、メンゴ。やっぱり先に住んでるやつがいたんだね。","ENG":"Whoa... Didn't know it was already occupied. Sorry.","TWN":"噢噢，抱歉，果然有房客呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잔해잖아요?! 수로에 둥지를 틀고 있었던 건가요?","JPN":"残骸ではないですか！？　水路に住み着いていたのですか？","ENG":"Is that not one of the Remains?! Has it been living down here all this time?","TWN":"這是殘骸嘛？！是在水道裡安家了嗎？"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_NPC_ESPR2_A","text":{"KOREA":"그, 그럼 밤마다 마루 밑에서 들리던 소리는 쥐가 아니라…….","JPN":"じゃ、じゃあ夜ごとに床下から聞こえていた音はネズミなどではなく……","ENG":"Th-then, the sound that was coming beneath us... It wasn't rats, but...","TWN":"那…那每天晚上從地板底下傳來的聲音不是老鼠……"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"우선 여기서 몸을 피하시죠. 저것들은 주민들을 동원해 막겠습니다.","JPN":"まずはここから離れましょう。あれらは住民を動員して止めます。","ENG":"Please leave this to us and leave. I will mobilize the residents to take care of it.","TWN":"你先離開這裡。我會動員居民來攔住這些東西。"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……아뇨! 저는 영지 안에 유해조수가 창궐하게 허락했던 적 없습니다!","JPN":"……いいえ！　私は領地内に有害鳥獣がはびこることを許可した覚えはありません！","ENG":"No! I have never given permission for harmful beasts to live in my estate!","TWN":"……不行！我不允許有害蟲在領地裡猖獗橫行！"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"영지의 관리도 맥크레디 가문의 의무예요. 제 손으로 직접 내쫓겠어요.","JPN":"領地の管理もまたマクレディー家も義務ですわ。私が追い出します。","ENG":"It is the MacCready family's duty to take care of the estate. I will get rid of it myself.","TWN":"管理領地也是麥克蕾蒂家族的義務。我要親手趕走它們。"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 탄약은 충분히 가져왔나요?","JPN":"リベット、弾丸は十分ですか？","ENG":"Rivet, did you bring enough bullets?","TWN":"里維，彈藥帶夠了嗎？"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"우리 머리통에 몇 발 쏘고 시작해도 될 만큼 챙겨 왔지~","JPN":"アタシたちの頭に何発か撃ってから始めてもいけるくらいの数は持ってきたよ～","ENG":"Yup! More than enough to put a few in our noggins as well!","TWN":"帶夠了，先往我們的腦袋上打幾槍再開始都行～"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"주민들이 대피할 시간을 벌어야 해요. 마음껏 실력 발휘하세요.","JPN":"住民が待避する時間を稼がなければなりませんわ。どうぞ存分に実力を発揮してください。","ENG":"We must give the residents enough time to evacuate. Give it your all.","TWN":"必須爭取時間讓居民們躲起來。盡情發揮你的實力吧。"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그~래? 그럼 고용주 부탁도 받았으니까 신나게 쏴 보실까!","JPN":"そ～お？　じゃあ、クライアントにも頼まれたことだし、いっちょぶっぱなしてみますか！","ENG":"Reaaaally? Well, since you gave me the green light, don't mind if I do!","TWN":"好～喔！既然雇主這麼要求了，那我就開心射擊了！"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};